class Solution {
    public boolean canConvertString(String s, String t, int k) {
        if (s.length() != t.length()) {
            return false;
        }
        int diff = 0;
        for (int i = 0; i < s.length(); i++) {
            diff += Math.abs(s.charAt(i) - t.charAt(i));
        }
        return diff <= k;
    }
}
